export type LineDataset = {
    label: string;
    data: number[];
    color?: string;
    fill?: boolean;
};
export type BarDataset = {
    label: string;
    data: number[];
    color?: string;
};
export type ScatterPoint = {
    x: number;
    y: number;
};
export type BubblePoint = {
    x: number;
    y: number;
    r: number;
};
export type ScatterDataset = {
    label: string;
    data: ScatterPoint[];
    color?: string;
};
export type BubbleDataset = {
    label: string;
    data: BubblePoint[];
    color?: string;
};
export type RadarDataset = {
    label: string;
    data: number[];
    color?: string;
    fill?: boolean;
};
